// Note: storage event does NOT fire in sessionStorage

const safeStorage = {
  get(key, defaultValue) {
    try {
      const raw = localStorage.getItem(key);
      if (raw === null) return defaultValue;
      return JSON.parse(raw);
    } catch {
      return defaultValue;
    }
  },

  set(key, value) {
    try {
      localStorage.setItem(key, JSON.stringify(value));
      return true;
    } catch (e) {
      if (e.name === 'QuotaExceededError') {
        console.warn('Storage full. Clearing old cache...');
        this.clearCache();
        // Retry after clearing
        try {
          localStorage.setItem(key, JSON.stringify(value));
          return true;
        } catch {}
      }
      return false;
    }
  },

  remove(key) {
    try { localStorage.removeItem(key); return true; } catch { return false; }
  },

  clearCache(prefix) {
    const toRemove = [];
    for (let i = 0; i < localStorage.length; i++) {
      const key = localStorage.key(i);
      if (key.startsWith(prefix || 'cache-')) {
        toRemove.push(key);
      }
    }
    toRemove.forEach(function(k) { localStorage.removeItem(k); });
  }
};

// Usage
safeStorage.set('prefs', { theme: 'dark' });
const prefs = safeStorage.get('prefs', { theme: 'light' });
console.log(prefs.theme); // 'dark'
